import React, {useRef, useContext} from 'react';
import { useNavigate } from 'react-router-dom';
import * as Styled from './styles';
import { ThemeContext } from 'styled-components';
import useMobile from '../../../helpers/hooks/useMobile';
import dataFormatString from '../../../helpers/functions/dataFormatString';
import categories from '../../../constants/categoriesColors';
import { useInView } from 'react-intersection-observer';
import useTablet from '../../../helpers/hooks/useTablet';

const BlogCard = ({ item }) => {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
    const {isBright} = useContext(ThemeContext);
    const navigate = useNavigate();
    const contentRef = useRef();
    const lastData = item.createdAt.slice(0,10);
    const isMobile = useMobile();
    const isTablet = useTablet();

    return (
        
        <Styled.CardContainer ref={ref} inView={inView} isMobile={isMobile} isTablet={isTablet} isBright={isBright}>   
            <Styled.Card onClick={() => navigate(`/blog/${item.id}`)}>
                <Styled.ImageContainer>
                    <Styled.CardImage src={item.previewImage}/>
                </Styled.ImageContainer>
                <Styled.CardContent>
                    <Styled.MetaDataContainer>
                        <Styled.CategoryText
                            color={isBright ? categories[item.category].bright : categories[item.category].dark}
                        >
                            {item.category}
                        </Styled.CategoryText>
                        <Styled.DataText>{dataFormatString(lastData)}</Styled.DataText>
                    </Styled.MetaDataContainer>
                    
                    <Styled.CardTitle>{item.title}</Styled.CardTitle>
                    <Styled.CardText>
                    {item.description}
                    </Styled.CardText>
                    <div style={{display: 'none'}} ref={contentRef} dangerouslySetInnerHTML={{__html: item.contents}} />
                </Styled.CardContent>
            </Styled.Card>
        </Styled.CardContainer>
    );
};

export default BlogCard;
