import React, { useState, useContext, useEffect } from 'react';
import * as Styled from './styles';
import useMobile from '../../../helpers/hooks/useMobile';
import BlogCard from '../../components/BlogCard';
import JsonData from '../../posts/output.json';
import CTASection from '../../../pages/_sections/CTASection';
import { ThemeContext } from 'styled-components';
import { useInView } from 'react-intersection-observer';
import useTablet from '../../../helpers/hooks/useTablet';
import setLoaderStatus from '../../../helpers/functions/setLoaderStatus';

const BlogHomePage = () => {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
    const {isBright} = useContext(ThemeContext);
    const [categories, setCategories] = useState({
        'All': true,
        'Development': false,
        'Business': false,
    });
    const [activeCategory, setActiveCategory] = useState('All');
    const isMobile = useMobile();
    const isTablet = useTablet();
    const cardsToRender = JsonData.data.map(item => {
        if(activeCategory === 'All' || item.category === activeCategory) {
            return <BlogCard key={item.id} item={item} isBright={isBright}/>;
        } else {
            return null;
        }
    }).filter(item => item);

    useEffect(()=>{
        setLoaderStatus(true);
        
        return setLoaderStatus(false);
    },[])

    return (
        <Styled.Layout isTablet={isTablet} isBright={isBright} isMobile={isMobile}>
            <Styled.BlogPageContainer ref={ref} inView={inView}>
                <Styled.TitleContainer>
                    <Styled.Title>Our blog</Styled.Title>
                </Styled.TitleContainer>
                <Styled.CategoriesContainer>
                    {Object.entries(categories).map(category => {
                        return (
                            <Styled.Category data-ccursor isBright={isBright} isActive={categories[category[0]]} key={category} onClick={() => {
                                const newState = {};
                                Object.keys(categories).forEach(item => newState[item] = item === category[0] ? true : false);
                                setActiveCategory(category[0]);
                                setCategories(newState);
                                }}>{category}</Styled.Category>)
                    })}
                </Styled.CategoriesContainer>
                <Styled.UpperCardsContainer>
                    {cardsToRender.map((item,index) => index < 3 && item)}
                </Styled.UpperCardsContainer>
                </Styled.BlogPageContainer>
                <CTASection isBright={isBright} />
                {cardsToRender.length > 2 && 
                    <Styled.CardsContainer>
                        {cardsToRender.map((item,index) => index > 2 && item)}
                    </Styled.CardsContainer>
                }
        </Styled.Layout>
    );
};

export default BlogHomePage;